/* Uran Khatola Factory — style.css */

:root {
  --bg:        #f5f0e8;
  --bg-alt:    #ede8dc;
  --border:    #b0a898;
  --text:      #1a1a2e;
  --text-muted:#5a5a6e;
  --accent:    #8b1a1a;   /* deep red — like old aviation manuals */
  --link:      #1a3a6e;
  --link-hover:#8b1a1a;
  --nav-bg:    #1a1a2e;
  --nav-text:  #e8e0d0;
  --max-width: 860px;
}

* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  background: var(--bg);
  color: var(--text);
  font-family: Georgia, "Times New Roman", serif;
  font-size: 17px;
  line-height: 1.7;
}

/* ── HEADER ── */
#site-header {
  background: var(--nav-bg);
  border-bottom: 3px solid var(--accent);
  text-align: center;
  padding: 18px 16px 12px;
}

#site-header h1 {
  font-family: "Courier New", Courier, monospace;
  font-size: 2rem;
  color: #e8e0d0;
  letter-spacing: 2px;
  text-transform: uppercase;
}

#site-header .tagline {
  font-size: 0.85rem;
  color: #a09880;
  letter-spacing: 1px;
  margin-top: 4px;
  font-style: italic;
}

/* ── NAV ── */
nav {
  background: var(--nav-bg);
  border-bottom: 2px solid var(--accent);
}

nav ul {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0;
}

nav ul li a {
  display: block;
  padding: 9px 18px;
  color: var(--nav-text);
  text-decoration: none;
  font-family: "Courier New", Courier, monospace;
  font-size: 0.85rem;
  letter-spacing: 1px;
  text-transform: uppercase;
  border-right: 1px solid #2e2e4e;
}

nav ul li:first-child a { border-left: 1px solid #2e2e4e; }

nav ul li a:hover,
nav ul li a.active {
  background: var(--accent);
  color: #fff;
}

/* ── LAYOUT ── */
#wrapper {
  max-width: var(--max-width);
  margin: 0 auto;
  padding: 0 16px;
  display: grid;
  grid-template-columns: 1fr 220px;
  gap: 0 28px;
  align-items: start;
}

#main  { padding: 28px 0; }
#sidebar { padding: 28px 0; border-left: 1px solid var(--border); padding-left: 20px; }

/* ── TYPOGRAPHY ── */
h1, h2, h3 {
  font-family: Georgia, serif;
  color: var(--text);
  line-height: 1.3;
}

h1 { font-size: 1.6rem; margin-bottom: 12px; }
h2 { font-size: 1.25rem; margin: 24px 0 8px; border-bottom: 1px solid var(--border); padding-bottom: 4px; }
h3 { font-size: 1.05rem; margin: 18px 0 6px; }

p  { margin-bottom: 14px; }

a  { color: var(--link); }
a:hover { color: var(--link-hover); text-decoration: underline; }

hr {
  border: none;
  border-top: 1px solid var(--border);
  margin: 24px 0;
}

/* ── PAGE TITLE BAR ── */
.page-title {
  background: var(--bg-alt);
  border-top: 3px solid var(--accent);
  border-bottom: 1px solid var(--border);
  padding: 14px 16px;
  margin-bottom: 0;
}

.page-title h1 {
  max-width: var(--max-width);
  margin: 0 auto;
  font-size: 1.4rem;
  font-family: "Courier New", Courier, monospace;
  letter-spacing: 1px;
}

/* ── HOME INTRO ── */
.intro-box {
  background: var(--bg-alt);
  border: 1px solid var(--border);
  border-left: 4px solid var(--accent);
  padding: 18px 20px;
  margin-bottom: 28px;
}

/* ── HOURS COUNTER ── */
.hours-table {
  width: 100%;
  border-collapse: collapse;
  font-family: "Courier New", Courier, monospace;
  font-size: 0.85rem;
  margin-bottom: 16px;
}

.hours-table td {
  padding: 5px 8px;
  border: 1px solid var(--border);
}

.hours-table td:last-child {
  text-align: right;
  font-weight: bold;
  color: var(--accent);
}

/* ── POST LIST (log index) ── */
.post-list { list-style: none; }

.post-list li {
  border-bottom: 1px solid var(--border);
  padding: 12px 0;
}

.post-list li:first-child { border-top: 1px solid var(--border); }

.post-list .post-date {
  font-family: "Courier New", Courier, monospace;
  font-size: 0.78rem;
  color: var(--text-muted);
  display: block;
  margin-bottom: 2px;
}

.post-list .post-cat {
  font-size: 0.75rem;
  background: var(--bg-alt);
  border: 1px solid var(--border);
  padding: 1px 6px;
  color: var(--text-muted);
  margin-left: 8px;
  font-family: "Courier New", Courier, monospace;
}

.post-list a {
  font-size: 1rem;
  font-weight: bold;
}

/* ── SINGLE POST ── */
.post-header {
  margin-bottom: 20px;
  padding-bottom: 12px;
  border-bottom: 2px solid var(--border);
}

.post-header h1 { font-size: 1.5rem; }

.post-meta {
  font-family: "Courier New", Courier, monospace;
  font-size: 0.8rem;
  color: var(--text-muted);
  margin-top: 6px;
}

.post-meta span { margin-right: 14px; }

.post-body img {
  max-width: 100%;
  height: auto;
  border: 1px solid var(--border);
  display: block;
  margin: 16px auto;
}

.post-body .img-caption {
  text-align: center;
  font-size: 0.8rem;
  color: var(--text-muted);
  font-style: italic;
  margin-top: -10px;
  margin-bottom: 16px;
}

.post-nav {
  display: flex;
  justify-content: space-between;
  margin-top: 32px;
  padding-top: 16px;
  border-top: 1px solid var(--border);
  font-size: 0.85rem;
  font-family: "Courier New", Courier, monospace;
}

/* ── SIDEBAR ── */
.sidebar-section {
  margin-bottom: 24px;
}

.sidebar-section h3 {
  font-family: "Courier New", Courier, monospace;
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 1px;
  background: var(--nav-bg);
  color: var(--nav-text);
  padding: 5px 8px;
  margin-bottom: 8px;
}

.sidebar-section ul { list-style: none; }

.sidebar-section ul li {
  border-bottom: 1px dotted var(--border);
  padding: 5px 0;
  font-size: 0.85rem;
}

.sidebar-section ul li a { font-size: 0.85rem; }

/* ── FOOTER ── */
footer {
  background: var(--nav-bg);
  border-top: 3px solid var(--accent);
  color: #a09880;
  text-align: center;
  padding: 18px 16px;
  font-family: "Courier New", Courier, monospace;
  font-size: 0.78rem;
  margin-top: 40px;
}

footer a { color: #c0b090; }

/* ── PLACEHOLDER IMAGE ── */
.img-placeholder {
  background: var(--bg-alt);
  border: 2px dashed var(--border);
  color: var(--text-muted);
  text-align: center;
  padding: 40px 20px;
  font-family: "Courier New", Courier, monospace;
  font-size: 0.8rem;
  margin: 16px 0;
}

/* ── TAGS ── */
.tags { margin-top: 16px; font-size: 0.8rem; }
.tags a {
  display: inline-block;
  background: var(--bg-alt);
  border: 1px solid var(--border);
  padding: 2px 8px;
  margin: 2px;
  color: var(--text-muted);
  text-decoration: none;
  font-family: "Courier New", Courier, monospace;
}
.tags a:hover { background: var(--accent); color: #fff; border-color: var(--accent); }

/* ── RESPONSIVE ── */
@media (max-width: 680px) {
  #wrapper {
    grid-template-columns: 1fr;
  }

  #sidebar {
    border-left: none;
    border-top: 2px solid var(--border);
    padding-left: 0;
    padding-top: 20px;
  }

  #site-header h1 { font-size: 1.4rem; }

  nav ul li a {
    padding: 8px 12px;
    font-size: 0.78rem;
  }

  .post-nav { flex-direction: column; gap: 8px; }
}

@media (max-width: 400px) {
  body { font-size: 15px; }
  #site-header h1 { font-size: 1.2rem; letter-spacing: 1px; }
}

